import React, { useState } from 'react';

const App = () => {
  const [message, setMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const handleTyping = () => {
    setIsTyping(true);
    setTimeout(() => {
      setIsTyping(false);
    }, 3000);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className='bg-[#B7D7CD] p-4 w-full max-w-md rounded-md shadow-md'>
        <div className='flex items-center mb-4'>
          <div className='bg-[#C06C88] p-2 rounded-full'></div>
          <div className='ml-2 text-lg font-bold'>John Doe</div>
        </div>
        <div className='border border-gray-600 rounded-md p-2 mb-4'>{isTyping ? 'Typing...' : ''}</div>
        <div className='border border-gray-600 rounded-md p-2'>
          <textarea
            className='w-full h-10 p-2 text-sm text-gray-700 focus:outline-none focus:ring focus:ring-[#411C56] focus:border-[#411C56]'
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder='Type a message'
          />
        </div>
        <div className='flex items-center justify-end mt-4'>
          <button className='bg-[#C06C88] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded-md'>Send</button>
        </div>
      </div>
    </div>
  );
};

export default App;
